import{_ as l,r as o,o as p,c as r,a as s,b as a,d as t,f as n}from"./app-cc861b06.js";const i={},c=n(`<h1 id="mysql集群" tabindex="-1"><a class="header-anchor" href="#mysql集群" aria-hidden="true">#</a> Mysql集群</h1><h2 id="一、安装mysql" tabindex="-1"><a class="header-anchor" href="#一、安装mysql" aria-hidden="true">#</a> 一、安装Mysql</h2><p>若是CentOS7.6，需要运行 rpm -qa | grep mari，查询mariadb相关安装包，因为CentOS 7.6会自带类MySQL数据库，会和mysql冲突，所以有安装包则删除：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">rpm</span> <span class="token parameter variable">-e</span> <span class="token parameter variable">--nodeps</span> mariadb-libs  <span class="token comment"># 删除</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div>`,4),d=s("strong",null,"CentOS7环境之RPM方式离线安装MySQL5.7",-1),m=s("br",null,null,-1),b={href:"https://downloads.mysql.com/archives/community/",target:"_blank",rel:"noopener noreferrer"},v=s("br",null,null,-1),u=s("br",null,null,-1),k=s("img",{src:"https://steven-kz.github.io/BlogImgs/imgaes/mysql/1.png",alt:"image.png",loading:"lazy"},null,-1),g=s("br",null,null,-1),h=n(`<div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token comment"># 在当前目录下（mysql）下创建一个 mysql-5.7 文件夹</span>
<span class="token function">mkdir</span> mysql-5.7.42
<span class="token comment"># 解压安装包到该目录下</span>
<span class="token function">tar</span> <span class="token parameter variable">-xvf</span> mysql-5.7.42-1.el7.x86_64.rpm-bundle.tar <span class="token parameter variable">-C</span> mysql-5.7.42
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>解压完成之后可以切换到 mysql-5.7 目录下查看解压后的文件<br>可以看到解压后的文件都是 rpm 文件，所以需要用到rpm包资源管理器相关的指令安装这些 rpm 的安装包<br>在安装执行 rpm 安装包之前先下载一些插件，因为 mysql 里面有些 rpm 的安装依赖于该插件。</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>yum <span class="token function">install</span> openssl-devel
<span class="token comment"># 和</span>
yum <span class="token parameter variable">-y</span> <span class="token function">install</span> libaio perl net-tools
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>安装完该插件之后，依次执行以下命令安装这些 rpm 包<br><br><img src="https://steven-kz.github.io/BlogImgs/imgaes/mysql/2.png" alt="image.png" loading="lazy"><br> 启动mysql</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>systemctl start mysqld  <span class="token comment"># 启动mysql服务</span>
systemctl status mysqld  <span class="token comment"># 查看mysql服务状态</span>
systemctl <span class="token builtin class-name">enable</span> mysqld  <span class="token comment">#设置开机启动</span>
systemctl daemon-reload  <span class="token comment"># 刷新所有修改过的配置文件</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>MySQL会自动为root生成密码，执行下面的命令可看到密码<br>grep &quot;password&quot;/var/log/mysqld.log （根目录执行）<br>拿到密码之后登陆mysql -u root -p</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token comment"># 执行如下语句更改root用户密码：</span>
ALTER <span class="token environment constant">USER</span> <span class="token environment constant">USER</span><span class="token punctuation">(</span><span class="token punctuation">)</span> IDENTIFIED BY <span class="token string">&#39;999999&#39;</span><span class="token punctuation">;</span>
<span class="token comment">#设置 validate_password_policy 的全局参数为 LOW，并将密码长度设置为你想要的长度：</span>
mysql<span class="token operator">&gt;</span> <span class="token builtin class-name">set</span> global <span class="token assign-left variable">validate_password_policy</span><span class="token operator">=</span>LOW<span class="token punctuation">;</span>
mysql<span class="token operator">&gt;</span> <span class="token builtin class-name">set</span> global <span class="token assign-left variable">validate_password_length</span><span class="token operator">=</span><span class="token number">9</span><span class="token punctuation">;</span>
<span class="token comment">#最后执行刷新MySQL的系统权限命令：</span>
FLUSH PRIVILEGES<span class="token punctuation">;</span> 
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>现在会发现远程连接不上mysql</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token comment"># 直接将root权限修改为可以通过远程访问(但不推荐)</span>
mysql<span class="token operator">&gt;</span> use mysql<span class="token punctuation">;</span>
mysql<span class="token operator">&gt;</span> UPDATE user SET <span class="token assign-left variable">Host</span><span class="token operator">=</span><span class="token string">&#39;%&#39;</span> WHERE <span class="token assign-left variable">User</span><span class="token operator">=</span><span class="token string">&#39;root&#39;</span><span class="token punctuation">;</span>
mysql<span class="token operator">&gt;</span> flush privileges<span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>添加防火墙</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token comment"># 打开防火墙                   </span>
systemctl start firewalld；
<span class="token comment">#放开3306端口</span>
firewall-cmd <span class="token parameter variable">--zone</span><span class="token operator">=</span>public --add-port<span class="token operator">=</span><span class="token number">3306</span>/tcp <span class="token parameter variable">--permanent</span>    
<span class="token comment">#重新加载配                                             </span>
firewall-cmd <span class="token parameter variable">--reload</span> 
<span class="token comment"># 查看防火墙所以开放端口</span>
firewall-cmd <span class="token parameter variable">--zone</span><span class="token operator">=</span>public --list-ports
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>mysql配置文件路径 /etc/my.cnf</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token punctuation">[</span>mysqld<span class="token punctuation">]</span>
<span class="token assign-left variable">port</span><span class="token operator">=</span><span class="token number">3307</span>         <span class="token comment">#设置端口号</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="二、开启bin-log" tabindex="-1"><a class="header-anchor" href="#二、开启bin-log" aria-hidden="true">#</a> 二、开启BIN-LOG</h2><p><strong>binlog基本概念</strong><br><strong>binlog基本概念</strong>二进制日志(binnary log)以事件形式记录了对MySQL数据库执行更改的所有操作。 binlog是记录所有数据库表结构变更（例如CREATE、ALTER TABLE、DROP等）以及表数据修改（INSERT、UPDATE、DELETE、TRUNCATE等）的二进制日志。不会记录SELECT和SHOW这类操作，因为这类操作对数据本身并没有修改，但可以通过查询通用日志来查看MySQL执行过的所有语句。<br>登录MySQL后，查看binlog状态sql如下：<br>show variables like &#39;%log_bin%&#39;;<br> 若未开启则需要开启<br>编辑配置文件配置开启binlog 放在mysqld下<br>编辑配置文件 vim /etc/my.cnf</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token comment">#设置唯一id</span>
server-id<span class="token operator">=</span><span class="token number">1</span>
<span class="token comment">##开启bin-log，产生的bin-log文件名即为bin-log.*</span>
log-bin<span class="token operator">=</span>mysql-bin
<span class="token comment">#指定bin-log为row类别，其他两种是statement、mixed</span>
<span class="token assign-left variable">binlog_format</span><span class="token operator">=</span>row
<span class="token comment"># 在 binlog 中记录完整的行数据</span>
binlog_row_image <span class="token operator">=</span> full
<span class="token comment">#对全部数据库开启则注释掉binlog-do-db即可</span>
<span class="token comment">#对指定的数据库开启bin-log，这里是对food数据库开启bin-log服务</span>
binlog-do-db<span class="token operator">=</span>food
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>配置完成后退出，然后重启我们的mysql服务<br>查看是否开启bin_log日志<br>mysql命令: show variables like &#39;log_%&#39;<br><img src="https://steven-kz.github.io/BlogImgs/imgaes/mysql/3.png" alt="image.png" loading="lazy"></p><h2 id="三、数据恢复" tabindex="-1"><a class="header-anchor" href="#三、数据恢复" aria-hidden="true">#</a> 三、数据恢复</h2><p>自行模拟删除数据</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>查看我们当前使用的binlog
show master status;
查看日志列表
show master logs;
查看binlog日志信息包括位置
show variables like &#39;log_%&#39;;
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><img src="https://steven-kz.github.io/BlogImgs/imgaes/mysql/4.png" alt="image.png" loading="lazy"><br><br><br> 当需要恢复数据时，为了防止恢复数据后影响最新业务，需要执行<span style="color:red;">flush logs</span><br> ，产生一个新的binlog文件，此时旧的binlog文件不会再有写入；<br><br> 进入到我们的binlog日志位置 /var/lib/mysql<br><br><img src="https://steven-kz.github.io/BlogImgs/imgaes/mysql/5.png" alt="image.png" loading="lazy"><br> 下面具体通过mysql-bin.000001来进行数据恢复<br> 恢复时需要在binlog中找到两个位置：</p><ul><li>数据恢复的起始位置</li><li>数据恢复的结束位置</li></ul><h3 id="_2-1-mysqlbinlog" tabindex="-1"><a class="header-anchor" href="#_2-1-mysqlbinlog" aria-hidden="true">#</a> 2.1 mysqlbinlog</h3><p><strong>只能正向回滚，不适用</strong></p><p>在服务器内执行：</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>通过mysqlbinlog将binlog转为sql，以方便查询具体位置
mysqlbinlog --set-charset=utf-8 /var/lib/mysql/mysql-bin.000001&gt;backuptmp.sql
查看生成的backuptmp.sql，最终确定需要恢复的起始位置为的行数
执行恢复数据
mysqlbinlog -v /var/lib/mysql/mysql-bin.000005 --start-position=299 --stop-position=1305 | mysql -uroot -p999999
如果执行提示se you are using a --stop-position or --stop-datetime that refers to an event in the middle of a statement. The event(s) from the partial statement have not been written to output.
则表示个参数指向了一个语句中间的事件。部分语句的事件尚未被写入输出。
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>说明如何定位起止行数：<br>并不是定位delete，drop的数据位置，而是寻找你create或Write的数据<br>举例：一条数据的inset如何定位<br><br><img src="https://steven-kz.github.io/BlogImgs/imgaes/mysql/6.png" alt="image.png" loading="lazy"></p><h3 id="_2-2-binlog2-sql" tabindex="-1"><a class="header-anchor" href="#_2-2-binlog2-sql" aria-hidden="true">#</a> 2.2 binlog2.sql</h3><p>推荐使用</p><p>只针对于mysql5.6 5.7，必须开启binlog日志 ，配置请在官网查看</p><p><strong>优势：可反编译 直接回滚,可筛选库筛选表非常的方便</strong></p>`,31),y={href:"https://github.com/danfengcao/binlog2sql",target:"_blank",rel:"noopener noreferrer"},q=n(`<div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token comment"># 安装工具</span>
yum <span class="token parameter variable">-y</span> <span class="token function">install</span> <span class="token function">git</span> python-pip 

<span class="token comment"># 克隆binlog2sql</span>
<span class="token function">git</span> clone https://github.com/danfengcao/binlog2sql.git <span class="token operator">&amp;&amp;</span> <span class="token builtin class-name">cd</span> binlog2sql
用pip命令来下载binlog2sql所需要的“requirements.txt”这个文本
pip <span class="token function">install</span> <span class="token parameter variable">-r</span> requirements.txt

<span class="token comment"># 安装位置</span>
<span class="token builtin class-name">cd</span> /mydata/binlog2sql/binlog2sql
<span class="token comment"># 执行回滚 配置在官网查看</span>
<span class="token comment"># 可根据mysqlbinlog找到删除的偏移量 根据偏移量去执行反编译sql，若不知偏移量也可直接全部反编译</span>
python binlog2sql.py <span class="token parameter variable">-h127.0.0.1</span> <span class="token parameter variable">-P3307</span> <span class="token parameter variable">-uroot</span> -p****** <span class="token parameter variable">-dfood</span> <span class="token parameter variable">-t</span> jjjfood_order <span class="token parameter variable">-B</span> <span class="token parameter variable">--flashback</span>  --start-file<span class="token operator">=</span>mysql-bin.000012 <span class="token operator">&gt;</span> rollback.sql --start-position<span class="token operator">=</span><span class="token number">3270</span> --stop-position<span class="token operator">=</span><span class="token number">4335</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>若误删整表，该如何操作</strong></p><p><strong>针对于delete from 表 删除表中所有数据</strong></p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token comment">#根据时间去查看是否为当时删除的数据</span>
python binlog2sql.py <span class="token parameter variable">-h127.0.0.1</span> <span class="token parameter variable">-P3307</span> <span class="token parameter variable">-uroot</span> -p****** <span class="token parameter variable">-dfood</span> <span class="token parameter variable">-t</span> jjjfood_center_menu  --start-file<span class="token operator">=</span><span class="token string">&#39;mysql-bin.000013&#39;</span>   --start-datetime<span class="token operator">=</span><span class="token string">&#39;2024-4-17 00:00:00&#39;</span>   --stop-datetime<span class="token operator">=</span><span class="token string">&#39;2024-04-17 16:51:58&#39;</span> 
<span class="token comment">#根据时间进行反编译执行sql</span>
python binlog2sql.py <span class="token parameter variable">-h127.0.0.1</span> <span class="token parameter variable">-P3307</span> <span class="token parameter variable">-uroot</span> -p****** <span class="token parameter variable">-dfood</span> <span class="token parameter variable">-t</span> jjjfood_center_menu  --start-file<span class="token operator">=</span><span class="token string">&#39;mysql-bin.000012&#39;</span>   <span class="token parameter variable">-B</span> <span class="token operator">&gt;</span> rollback.sql --start-datetime<span class="token operator">=</span><span class="token string">&#39;2024-4-17 00:00:00&#39;</span>   --stop-datetime<span class="token operator">=</span><span class="token string">&#39;2024-04-17 16:51:58&#39;</span> 
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>针对于DROP删除</strong></p><p>1.被drop删除之后，binlog2无法查询和反编译到增删改语句</p><p>2.执行flush logs</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>python binlog2sql.py <span class="token parameter variable">-h127.0.0.1</span> <span class="token parameter variable">-P3307</span> <span class="token parameter variable">-uroot</span> <span class="token parameter variable">-p999999</span> <span class="token parameter variable">-dfood</span> <span class="token parameter variable">-t</span> jjjfood_product_unit --start-file<span class="token operator">=</span><span class="token string">&#39;mysql-bin.000016&#39;</span>  <span class="token operator">&gt;</span> rollback.sql --start-datetime<span class="token operator">=</span><span class="token string">&#39;2024-4-17 00:00:00&#39;</span>   --stop-datetime<span class="token operator">=</span><span class="token string">&#39;2024-04-17 16:51:58&#39;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>3.从最初的binlog日志开始找create 表语句/或者是备份的表结构在数据库中添加(有表结构才会进行编译)</p><p>4.在flush logs之前所有的binlog日志文件执行上述命令，讲sql copy 一次执行恢复数据</p><h2 id="四、主从复制" tabindex="-1"><a class="header-anchor" href="#四、主从复制" aria-hidden="true">#</a> 四、主从复制</h2><p>二进制日志（BINLOG）记录了所有的 DDL（数据定义语言）语句和 DML（数据操纵语言）语句，但是不包括数据查询语句。此日志对于灾难时的数据恢复起着极其重要的作用，MySQL的主从复制， 就是通过该binlog实现的<br>主从复制是为了读写分离，减轻服务器压力，起到负载均衡的作用。<br><br><img src="https://steven-kz.github.io/BlogImgs/imgaes/mysql/7.png" alt="image.png" loading="lazy"><br> Amoeba (变形虫)。由陈思儒开发，其曾就职于阿里巴巴。该程序用Java语言进行开发,阿里巴巴将其用于生产环境。它不支持事务和存储过程。<br>实现过程<br>1、客户端访问代理服务器<br>2、代理服务器写入到主服务器<br>3、主服务器将增删改写入自己二进制日志<br>4、从服务器将主服务器的二进制日志同步至自己中继日志<br>5、从服务器重放中继日志到数据库中<br>6、客户端读，则代理服务器直接访问从服务器<br>7、降低负载，起到负载均衡作用</p><h3 id="_4-1-主库mysql配置" tabindex="-1"><a class="header-anchor" href="#_4-1-主库mysql配置" aria-hidden="true">#</a> 4.1 主库Mysql配置</h3><p>首先配置主库，开启binlog日志</p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code>vim <span class="token operator">/</span>etc<span class="token operator">/</span>my<span class="token punctuation">.</span>cnf
server<span class="token operator">-</span>id <span class="token operator">=</span> <span class="token number">1</span>
log<span class="token operator">-</span>bin<span class="token operator">=</span>master<span class="token operator">-</span>bin							#添加，主服务器开启二进制日志
log<span class="token operator">-</span>slave<span class="token operator">-</span>updates<span class="token operator">=</span><span class="token boolean">true</span>						#添加，允许从服务器更新二进制日志

systemctl restart mysqld
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>执行下面SQL，记录下结果中<strong>File</strong>和**Position（偏移量）**的值，用于后续复制开始的位置</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>show master status;
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p><strong>创建数据同步的用户并授权</strong></p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token constant">GRANT</span> <span class="token constant">REPLICATION</span> <span class="token constant">SLAVE</span> <span class="token constant">ON</span> <span class="token operator">*</span><span class="token punctuation">.</span>* <span class="token keyword">to</span> &#39;copyUser<span class="token char">&#39;@&#39;</span><span class="token operator">%</span>&#39; identified by &#39;<span class="token class-name">Root</span><span class="token annotation punctuation">@123456</span>&#39;<span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>上面SQL的作用是创建一个用户,并且给用户授予REPLICATION SLAVE权限。常用于建立复制时所需要用到的用户权限，也就是slave必须被master授权具有该权限的用户，才能通过该用户复制</p><h3 id="_4-2-从库mysql配置" tabindex="-1"><a class="header-anchor" href="#_4-2-从库mysql配置" aria-hidden="true">#</a> 4.2 从库Mysql配置</h3><p>修改Mysql数据库的配置文件/etc/my.cnf 后重启mysql</p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code>vim <span class="token operator">/</span>etc<span class="token operator">/</span>my<span class="token punctuation">.</span>cnf
server<span class="token operator">-</span>id <span class="token operator">=</span> <span class="token number">2</span>						#修改，注意id与<span class="token class-name">Master</span>的不同，两个<span class="token class-name">Slave</span>的id也要不同
relay<span class="token operator">-</span>log<span class="token operator">=</span>relay<span class="token operator">-</span>log<span class="token operator">-</span>bin						#添加，开启中继日志，从主服务器上同步日志文件记录到本地
relay<span class="token operator">-</span>log<span class="token operator">-</span>index<span class="token operator">=</span>slave<span class="token operator">-</span>relay<span class="token operator">-</span>bin<span class="token punctuation">.</span>index		#添加，定义中继日志文件的位置和名称

systemctl restart mysqld
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>登录Mysql数据库，设置主库地址及同步位置</p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code>change master <span class="token keyword">to</span> <span class="token namespace">master_host</span><span class="token operator">=</span>&#39;<span class="token number">8.139</span><span class="token number">.254</span><span class="token number">.175</span>&#39;<span class="token punctuation">,</span>master_port<span class="token operator">=</span><span class="token number">3307</span><span class="token punctuation">,</span>master_user<span class="token operator">=</span>&#39;copyUser&#39;<span class="token punctuation">,</span>master_password<span class="token operator">=</span>&#39;<span class="token class-name">Root</span><span class="token annotation punctuation">@123456</span>&#39;<span class="token punctuation">,</span>master_log_file<span class="token operator">=</span>&#39;mysql<span class="token operator">-</span>bin<span class="token punctuation">.</span><span class="token number">000008</span>&#39;<span class="token punctuation">,</span>master_log_pos<span class="token operator">=</span><span class="token number">154</span><span class="token punctuation">;</span>
 
start slave<span class="token punctuation">;</span>

# 如果配置错了停止掉重新配置即可
stop slave<span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>参数说明<br>A. master_host : 主库的IP地址 ，master_port：指定端口<br>B. master_user : 访问主库进行主从复制的用户名(上面在主库创建的)<br>C. master_password : 访问主库进行主从复制的用户名对应的密码<br>D. master_log_file : 从哪个日志文件开始同步(上述查询master状态中展示的有)<br>E. master_log_pos : 从指定日志文件的哪个位置开始同步(上述查询master状态中展示的有)<br><strong>查看从数据库的状态</strong></p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code>show slave status\\<span class="token class-name">G</span><span class="token punctuation">;</span>	  #查看 <span class="token class-name">Slave</span> 状态
<span class="token comment">//确保 IO 和 SQL 线程都是 Yes，代表同步正常。</span>
<span class="token class-name">Slave_IO_Running</span><span class="token operator">:</span> <span class="token class-name">Yes</span>	  #负责与主机的io通信
<span class="token class-name">Slave_SQL_Running</span><span class="token operator">:</span> <span class="token class-name">Yes</span>    #负责自己的slave mysql进程
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>状态信息中的 Slave_IO_running 和 Slave_SQL_running 可以看出主从同步是否就绪，如果这两个参数全为Yes，表示主从同步已经配置完成。<br><strong>注意：一定要保证主库数据为空或从库必须有当前主库数据否则删除/修改时主从复制会失败</strong><br><img src="https://steven-kz.github.io/BlogImgs/imgaes/mysql/8.png" alt="image.png" loading="lazy"><br><img src="https://steven-kz.github.io/BlogImgs/imgaes/mysql/9.png" alt="image.png" loading="lazy"></p><h2 id="五、读写分离" tabindex="-1"><a class="header-anchor" href="#五、读写分离" aria-hidden="true">#</a> 五、读写分离</h2><h3 id="_5-1-amoeba服务器配置" tabindex="-1"><a class="header-anchor" href="#_5-1-amoeba服务器配置" aria-hidden="true">#</a> 5.1 Amoeba服务器配置</h3>`,30),f={href:"https://sourceforge.net/projects/amoeba/files/Amoeba%20for%20mysql/2.2.x/amoeba-mysql-binary-2.2.0.tar.gz/download",target:"_blank",rel:"noopener noreferrer"},_=s("br",null,null,-1),x=n(`<div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code>yum install <span class="token operator">-</span>y java<span class="token operator">-</span><span class="token number">1.8</span><span class="token number">.0</span><span class="token operator">-</span>openjdk<span class="token operator">-</span>devel<span class="token punctuation">.</span>x86_64
java <span class="token operator">-</span>version
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>配置环境变量 AMOEBA_HOME 变形虫的安装路径</p><div class="language-powershell line-numbers-mode" data-ext="powershell"><pre class="language-powershell"><code>vim <span class="token operator">/</span>etc/profile

export JAVA_HOME=<span class="token operator">/</span>usr/lib/jvm/java-1<span class="token punctuation">.</span>8<span class="token punctuation">.</span>0-openjdk   <span class="token comment"># Java安装路径</span>
export PATH=<span class="token variable">$JAVA_HOME</span><span class="token operator">/</span>bin:<span class="token variable">$PATH</span>
export CLASSPATH=<span class="token punctuation">.</span>:<span class="token variable">$JAVA_HOME</span><span class="token operator">/</span>lib:<span class="token variable">$JAVA_HOME</span><span class="token operator">/</span>jre/lib
export AMOEBA_HOME=<span class="token operator">/</span>mydata/amoeba
export PATH=<span class="token variable">$PATH</span>:<span class="token variable">$AMOEBA_HOME</span><span class="token operator">/</span>bin

source <span class="token operator">/</span>etc/profile	
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>安装 Amoeba软件</p><div class="language-powershell line-numbers-mode" data-ext="powershell"><pre class="language-powershell"><code>mkdir <span class="token operator">/</span>mydata/amoeba
tar zxvf <span class="token operator">/</span>opt/amoeba-mysql-binary-2<span class="token punctuation">.</span>2<span class="token punctuation">.</span>0<span class="token punctuation">.</span>tar<span class="token punctuation">.</span>gz <span class="token operator">-</span>C <span class="token operator">/</span>mydata/amoeba/
chmod <span class="token operator">-</span>R 755 <span class="token operator">/</span>mydata/amoeba/
<span class="token comment"># 开启amoeba</span>
<span class="token operator">/</span>mydata/amoeba/bin/amoeba
<span class="token comment"># 如显示amoeba start|stop 说明安装成功</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>Amoeba启动错误：</strong><br>The stack size specified is too small, Specify at least 160k<br>Error: Could not create the Java Virtual Machine.<br>Error: A fatal exception has occurred. Program will exit.<br>解决方法：<br>打开bin目录下 的amoeba启动文件<br># vim amoeba<br>DEFAULT_OPTS=&quot;-server -Xms256m -Xmx256m -Xss128k&quot;<br>修改为：<br>DEFAULT_OPTS=&quot;-server -Xms256m -Xmx256m -Xss256k&quot;</p><h3 id="_5-2-在主从服务器的mysql上授权" tabindex="-1"><a class="header-anchor" href="#_5-2-在主从服务器的mysql上授权" aria-hidden="true">#</a> 5.2 在主从服务器的mysql上授权</h3><p><strong>先在Master、Slave1 的mysql上开放权限给 Amoeba 访问</strong></p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">grant</span> <span class="token keyword">all</span> <span class="token keyword">on</span> <span class="token operator">*</span><span class="token punctuation">.</span><span class="token operator">*</span> <span class="token keyword">to</span> test<span class="token variable">@&#39;123.56.114.%&#39;</span> identified <span class="token keyword">by</span> <span class="token string">&#39;tnpXL%^Kbrj^8bRX&#39;</span><span class="token punctuation">;</span> 
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h3 id="_5-3-配置-amoeba读写分离" tabindex="-1"><a class="header-anchor" href="#_5-3-配置-amoeba读写分离" aria-hidden="true">#</a> 5.3 配置 Amoeba读写分离</h3><p><strong>amoeba代理服务器配置amoeba服务</strong></p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token builtin class-name">cd</span> /mydata/amoeba/conf/

<span class="token function">cp</span> amoeba.xml amoeba.xml.bak
<span class="token function">vim</span> amoeba.xml		<span class="token comment">#修改amoeba配置文件</span>

<span class="token operator">&lt;</span>property <span class="token assign-left variable">name</span><span class="token operator">=</span><span class="token string">&quot;user&quot;</span><span class="token operator">&gt;</span>amoeba<span class="token operator">&lt;</span>/property<span class="token operator">&gt;</span>
<span class="token operator">&lt;</span>property <span class="token assign-left variable">name</span><span class="token operator">=</span><span class="token string">&quot;password&quot;</span><span class="token operator">&gt;</span>amoeba<span class="token operator">&lt;</span>/property<span class="token operator">&gt;</span>
<span class="token comment">#---------115修改 设置默认地址为master-----------------------------</span>
<span class="token operator">&lt;</span>property <span class="token assign-left variable">name</span><span class="token operator">=</span><span class="token string">&quot;defaultPool&quot;</span><span class="token operator">&gt;</span>master<span class="token operator">&lt;</span>/property<span class="token operator">&gt;</span>
<span class="token comment">#---------117去掉注释–------------------------</span>
<span class="token operator">&lt;</span>property <span class="token assign-left variable">name</span><span class="token operator">=</span><span class="token string">&quot;writePool&quot;</span><span class="token operator">&gt;</span>master<span class="token operator">&lt;</span>/property<span class="token operator">&gt;</span>
<span class="token operator">&lt;</span>property <span class="token assign-left variable">name</span><span class="token operator">=</span><span class="token string">&quot;readPool&quot;</span><span class="token operator">&gt;</span>slaves<span class="token operator">&lt;</span>/property<span class="token operator">&gt;</span>

</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">cp</span> dbServers.xml dbServers.xml.bak


<span class="token function">vim</span> dbServers.xml
<span class="token comment"># 文件中的port是mysql集群的端口号 需保持一致</span>
注释作用：默认进入test库 以防mysql中没有test库时，会报错
<span class="token operator">&lt;</span><span class="token operator">!</span>-- mysql schema
<span class="token operator">&lt;</span>property <span class="token assign-left variable">name</span><span class="token operator">=</span><span class="token string">&quot;schema&quot;</span><span class="token operator">&gt;</span>test<span class="token operator">&lt;</span>/property<span class="token operator">&gt;</span>
--<span class="token operator">&gt;</span>

<span class="token operator">&lt;</span><span class="token operator">!</span>-- mysql user --<span class="token operator">&gt;</span>
<span class="token operator">&lt;</span>property <span class="token assign-left variable">name</span><span class="token operator">=</span><span class="token string">&quot;user&quot;</span><span class="token operator">&gt;</span>test<span class="token operator">&lt;</span>/property<span class="token operator">&gt;</span>
<span class="token operator">&lt;</span>property <span class="token assign-left variable">name</span><span class="token operator">=</span><span class="token string">&quot;password&quot;</span><span class="token operator">&gt;</span>tnpXL%^Kbrj^8bRX<span class="token operator">&lt;</span>/property<span class="token operator">&gt;</span>

<span class="token comment">#---------设置主服务器的名Master------------------</span>
<span class="token operator">&lt;</span>dbServer <span class="token assign-left variable">name</span><span class="token operator">=</span><span class="token string">&quot;master&quot;</span>  <span class="token assign-left variable">parent</span><span class="token operator">=</span><span class="token string">&quot;abstractServer&quot;</span><span class="token operator">&gt;</span>
<span class="token operator">&lt;</span>property <span class="token assign-left variable">name</span><span class="token operator">=</span><span class="token string">&quot;ipAddress&quot;</span><span class="token operator">&gt;</span><span class="token number">8.139</span>.254.17<span class="token operator"><span class="token file-descriptor important">5</span>&lt;</span>/property<span class="token operator">&gt;</span>

<span class="token comment">#---------设置从服务器的名slave1-----------------</span>
<span class="token operator">&lt;</span>dbServer <span class="token assign-left variable">name</span><span class="token operator">=</span><span class="token string">&quot;slave1&quot;</span>  <span class="token assign-left variable">parent</span><span class="token operator">=</span><span class="token string">&quot;abstractServer&quot;</span><span class="token operator">&gt;</span>
<span class="token operator">&lt;</span>property <span class="token assign-left variable">name</span><span class="token operator">=</span><span class="token string">&quot;ipAddress&quot;</span><span class="token operator">&gt;</span><span class="token number">47.98</span>.187.<span class="token operator"><span class="token file-descriptor important">1</span>&lt;</span>/property<span class="token operator">&gt;</span>

<span class="token comment">#---------复制上面设置从服务器2的名slave2和地址---</span>
<span class="token operator">&lt;</span>dbServer <span class="token assign-left variable">name</span><span class="token operator">=</span><span class="token string">&quot;slave2&quot;</span>  <span class="token assign-left variable">parent</span><span class="token operator">=</span><span class="token string">&quot;abstractServer&quot;</span><span class="token operator">&gt;</span>
<span class="token operator">&lt;</span>property <span class="token assign-left variable">name</span><span class="token operator">=</span><span class="token string">&quot;ipAddress&quot;</span><span class="token operator">&gt;</span><span class="token number">192.168</span>.172.3<span class="token operator"><span class="token file-descriptor important">0</span>&lt;</span>/property<span class="token operator">&gt;</span>

<span class="token comment">#---------修改后的65或66修改-------------------------------------</span>
<span class="token operator">&lt;</span>dbServer <span class="token assign-left variable">name</span><span class="token operator">=</span><span class="token string">&quot;slaves&quot;</span> <span class="token assign-left variable">virtual</span><span class="token operator">=</span><span class="token string">&quot;true&quot;</span><span class="token operator">&gt;</span>
<span class="token comment">#---------71修改----------------------------------------</span>
<span class="token operator">&lt;</span>property <span class="token assign-left variable">name</span><span class="token operator">=</span><span class="token string">&quot;poolNames&quot;</span><span class="token operator">&gt;</span>slave1,slave<span class="token operator"><span class="token file-descriptor important">2</span>&lt;</span>/property<span class="token operator">&gt;</span>

/mydata/amoeba/bin/amoeba start<span class="token operator">&amp;</span>	 <span class="token comment">#启动Amoeba软件，按ctrl+c 返回</span>
<span class="token function">netstat</span> <span class="token parameter variable">-anpt</span> <span class="token operator">|</span> <span class="token function">grep</span> <span class="token function">java</span>	     <span class="token comment">#查看8066端口是否开启，默认端口为TCP 8066</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><figure><img src="https://steven-kz.github.io/BlogImgs/imgaes/mysql/10.png" alt="image.png" tabindex="0" loading="lazy"><figcaption>image.png</figcaption></figure><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token comment"># 打开防火墙                   </span>
systemctl start firewalld
firewall-cmd <span class="token parameter variable">--zone</span><span class="token operator">=</span>public --add-port<span class="token operator">=</span><span class="token number">8066</span>/tcp <span class="token parameter variable">--permanent</span>    
<span class="token comment">#重新加载配                                             </span>
firewall-cmd <span class="token parameter variable">--reload</span> 
<span class="token comment"># 查看防火墙所以开放端口</span>
firewall-cmd <span class="token parameter variable">--zone</span><span class="token operator">=</span>public --list-ports
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>验证是否成功 云服务器切记开放安全组后，启动amoeba</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>客户端连接amoeba或使用本地连接amoeba
mysql <span class="token parameter variable">-u</span> amoeba <span class="token parameter variable">-pamoeba</span> <span class="token parameter variable">-h</span> <span class="token number">123.56</span>.114.90 <span class="token parameter variable">-P8066</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p><img src="https://steven-kz.github.io/BlogImgs/imgaes/mysql/11.png" alt="image.png" loading="lazy"><br><br>Java连接mysql若报错请切换版本至<span>&quot;&lt;mysql.version&gt;5.1.24&lt;/mysql.version&gt;&quot;</span><br><span style="color:red;">经测试amoeba确实不支持事务，请根据情况使用，当然也可以通过多数据源的方式去实现读写分离(较麻烦)</span></p><p><strong>总结：</strong><br><strong>mysql主从复制原理</strong><br><strong>slave节点与主节点进行连接，建立主从关系，并把从哪开始同步，及哪个日志文件都一并发送到master</strong><br><strong>master将修改的数据保存到binlog中</strong><br><strong>master开启binlog dump线程，将binlog日志推送到连接的slave中</strong><br><strong>slave接受到推送的binlog，slave开启IO线程将数据写到中继日志(relay log)中</strong><br><strong>slave同时还会开启一个SQL线程，对比中继日志中新增的内容，并且解析SQL，回放数据到从数据库中</strong></p><p><strong>面试题：</strong><br><strong>1.如何查看主从同步状态是否成功</strong><br>show slave status \\G<br>show master status\\G<br><strong>2.如果I/O和sql不是yes呢，你是如何排查的</strong><br>先看last errno有几个错误 有什么错误等等都有信息显示<br>网络不通<br>my.cnf配置有问题<br>密码、file文件名、pos偏移量不对<br>防火墙没有关闭<br><strong>3.show slave status \\G能看到哪些信息（比较重要的）</strong><br>io状态 两个线程的yes<br>Last_Errno,Last_Error**<br>slave的SQL线程读取日志参数的的错误数量和错误消息。错误数量为0并且消息为空字符串表示没有错误；<br>如果Last_Error值不是空值，它也会在从属服务器的错误日志中作为消息显示。<br><strong>4.主从复制慢（延迟）有哪些可能</strong><br>从库硬件比主库差，导致复制延迟<br>主从复制单线程，如果主库写并发太大，来不及传送到从库，就会导致延迟。升级更高版本的mysql<br>可以支持多线程复制<br>慢SQL语句过多<br>网络延迟<br>master负载：主库读写压力大，导致复制延迟，架构的前端要加buffer及缓存层<br>slave负载：一般的做法是，使用多台slave来分摊读请求，再从这些slave中取一台专用的服务器，只作为备份用，不进行其他任何操作.<br><strong>5.mysql主从同步读写分离的三个账号</strong><br>主从同步（数据库互相授权的账号）<br>amoeba（客户端访问amoeba）<br>amoeba（amoeba访问数据库集群）</p>`,20);function S(w,A){const e=o("ExternalLinkIcon");return p(),r("div",null,[c,s("p",null,[d,m,a("官网下载Mysql："),s("a",b,[a("https://downloads.mysql.com/archives/community/"),t(e)]),v,u,k,g,a(" 上传至服务器指定位置")]),h,s("p",null,[a("官网："),s("a",y,[a("https://github.com/danfengcao/binlog2sql"),t(e)])]),q,s("p",null,[a("下载地址："),s("a",f,[a("https://sourceforge.net/projects/amoeba/files/Amoeba%20for%20mysql/2.2.x/amoeba-mysql-binary-2.2.0.tar.gz/download"),t(e)]),_,a("因为Amoeba是基于jdk1.5版本开发的，所以官方推荐使用1.5或者1.6版本，高版本不建议使用。")]),x])}const L=l(i,[["render",S],["__file","MysqlService.html.vue"]]);export{L as default};
